import React, { useEffect, useState } from "react";
import axios from "axios";
import "./SellerDashboard.css";

function SellerDashboard() {
  const [products, setProducts] = useState([]);
  const [form, setForm] = useState({
    name: "",
    description: "",
    category: "",
    price: "",
    image: ""
  });
  const [editingProduct, setEditingProduct] = useState(null);

  // Fetch all products
  const fetchProducts = async () => {
    try {
      const res = await axios.get("http://localhost:5000/api/products");
      setProducts(res.data);
    } catch (err) {
      console.error("Error fetching products:", err);
    }
  };

  useEffect(() => {
    fetchProducts();
  }, []);

  // Handle input change
  const handleChange = (e) => {
    setForm({ ...form, [e.target.name]: e.target.value });
  };

  // Submit form
  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      if (editingProduct) {
        // Update product
        await axios.put(
          `http://localhost:5000/api/products/${editingProduct._id}`,
          form
        );
        alert("✅ Product updated!");
        setEditingProduct(null);
      } else {
        // Add product
        await axios.post("http://localhost:5000/api/products", form);
        alert("✅ Product added!");
      }
      setForm({ name: "", description: "", category: "", price: "", image: "" });
      fetchProducts();
    } catch (err) {
      console.error(err);
      alert("❌ Failed to save product");
    }
  };

  // Edit product
  const handleEdit = (product) => {
    setForm({
      name: product.name,
      description: product.description,
      category: product.category,
      price: product.price,
      image: product.image,
    });
    setEditingProduct(product);
  };

  // Delete product
  const handleDelete = async (id) => {
    if (!window.confirm("Are you sure you want to delete this product?")) return;
    try {
      await axios.delete(`http://localhost:5000/api/products/${id}`);
      alert("🗑️ Product deleted!");
      fetchProducts();
    } catch (err) {
      console.error(err);
      alert("❌ Failed to delete product");
    }
  };

  return (
    <div className="seller-dashboard">
      {/* Sidebar */}
      <aside className="sidebar">
        <h1 className="logo">Seller Panel</h1>
        <nav>
          <ul>
            <li className="active">➕ Add Product</li>
            <li>📦 Product List</li>
            <li>📝 Orders</li>
          </ul>
        </nav>
      </aside>

      {/* Main Content */}
      <main className="main-content">
        {/* Product Form */}
        <form onSubmit={handleSubmit} className="product-form">
          <h3>{editingProduct ? "✏️ Edit Product" : "➕ Add New Product"}</h3>

          <div className="form-grid">
            <div className="form-group">
              <label>Product Name</label>
              <input
                type="text"
                name="name"
                placeholder="Enter product name"
                value={form.name}
                onChange={handleChange}
                required
              />
            </div>

            <div className="form-group">
              <label>Category</label>
              <select
                name="category"
                value={form.category}
                onChange={handleChange}
                required
              >
                <option value="">Select Category</option>
                <option>Earphone</option>
                <option>Smartphone</option>
                <option>Laptop</option>
                <option>Smartwatch</option>
                <option>Other</option>
              </select>
            </div>

            <div className="form-group full-width">
              <label>Description</label>
              <textarea
                name="description"
                placeholder="Enter product description"
                value={form.description}
                onChange={handleChange}
              />
            </div>

            <div className="form-group">
              <label>Price (₹)</label>
              <input
                type="number"
                name="price"
                placeholder="0"
                value={form.price}
                onChange={handleChange}
                required
              />
            </div>

            <div className="form-group">
              <label>Image URL</label>
              <input
                type="text"
                name="image"
                placeholder="https://example.com/product.jpg"
                value={form.image}
                onChange={handleChange}
                required
              />
            </div>
          </div>

          {/* Live Preview of Image */}
          {form.image && (
            <div className="preview">
              <p>Preview:</p>
              <img src={form.image} alt="Preview" />
            </div>
          )}

          <button type="submit" className="submit-btn">
            {editingProduct ? "Update Product" : "Add Product"}
          </button>
        </form>

        {/* Product List */}
        <h3 className="list-title">📦 Your Products</h3>
        <ul className="product-list">
          {products.map((product) => (
            <li key={product._id} className="product-item">
              <img src={product.image} alt={product.name} />
              <div className="product-info">
                <h4>{product.name}</h4>
                <p>₹{product.price}</p>
                <span>{product.category}</span>
              </div>
              <div className="actions">
                <button onClick={() => handleEdit(product)} className="edit-btn">
                  ✏️ Edit
                </button>
                <button
                  onClick={() => handleDelete(product._id)}
                  className="delete-btn"
                >
                  🗑️ Delete
                </button>
              </div>
            </li>
          ))}
        </ul>
      </main>
    </div>
  );
}

export default SellerDashboard;
